// Pull the dictated text out of YOUR inbound source and normalise it.
// Replace the 'Inbound message' webhook with your provider's trigger (WhatsApp
// Business Cloud, Telegram, Messenger, an email node, …) and edit the field
// pick below to match its payload. The captured line is whatever the glasses
// dictated — e.g. "Prefrontal, dentist wants me back in six months". The
// server strips the leading "Prefrontal," address itself, so send it verbatim.
const j = $json.body ?? $json;
const text = (j.text || j.message || j.Body || j.content || '').toString().trim();
return { json: { text } };

// Build a short spoken confirmation the glasses can read back to you. /observe
// returns { count, proposals:[{summary}] }. count 0 means the sensor found
// nothing worth proposing (or the local model was unreachable) — say so, so a
// hands-free capture is never a silent drop.
const r = $json;
const n = r.count || 0;
let reply;
if (!n) {
  reply = "Heard you, but nothing to file from that — captured no proposal.";
} else {
  const first = (r.proposals && r.proposals[0] && r.proposals[0].summary) || 'a note';
  reply = n === 1
    ? `Captured: ${first}. Review it when you're back.`
    : `Captured ${n} things (${first}, …). Review them when you're back.`;
}
return { json: { reply } };
